/**
 * Redaction utilities for logging sensitive data
 * Never log tokens, secrets, or PII in production
 */

const REDACTED = '[REDACTED]';

/**
 * Sensitive field patterns to redact
 */
const SENSITIVE_PATTERNS = [
  /token/i,
  /secret/i,
  /password/i,
  /key/i,
  /authorization/i,
  /bearer/i,
  /api[_-]?key/i,
  /access[_-]?token/i,
  /refresh[_-]?token/i,
  /client[_-]?secret/i,
];

/**
 * Check if a field name is sensitive
 */
function isSensitiveField(fieldName: string): boolean {
  return SENSITIVE_PATTERNS.some(pattern => pattern.test(fieldName));
}

/**
 * Redact sensitive fields in an object
 */
export function redactObject<T extends Record<string, any>>(obj: T): T {
  if (!obj || typeof obj !== 'object') {
    return obj;
  }

  const redacted: any = Array.isArray(obj) ? [] : {};

  for (const [key, value] of Object.entries(obj)) {
    if (isSensitiveField(key)) {
      redacted[key] = REDACTED;
    } else if (value && typeof value === 'object') {
      redacted[key] = redactObject(value);
    } else {
      redacted[key] = value;
    }
  }

  return redacted;
}

/**
 * Redact sensitive parts of a URL (query params, auth headers)
 */
export function redactUrl(url: string): string {
  try {
    const urlObj = new URL(url);
    
    // Redact sensitive query parameters
    const params = new URLSearchParams(urlObj.search);
    for (const [key] of params.entries()) {
      if (isSensitiveField(key)) {
        params.set(key, REDACTED);
      }
    }
    
    urlObj.search = params.toString();
    return urlObj.toString();
  } catch {
    // If URL parsing fails, just return as-is
    return url;
  }
}

/**
 * Redact bearer tokens from authorization headers
 */
export function redactAuthHeader(header: string): string {
  if (!header) return header;
  
  // Redact Bearer tokens
  if (header.toLowerCase().startsWith('bearer ')) {
    return `Bearer ${REDACTED}`;
  }
  
  return REDACTED;
}

/**
 * Safe logger that automatically redacts sensitive data
 */
export const safeLog = {
  info: (message: string, data?: any) => {
    console.info(message, data ? redactObject(data) : '');
  },
  
  warn: (message: string, data?: any) => {
    console.warn(message, data ? redactObject(data) : '');
  },
  
  error: (message: string, error?: any) => {
    const errorData = error instanceof Error 
      ? { message: error.message, stack: error.stack }
      : error;
    console.error(message, errorData ? redactObject(errorData) : '');
  },
  
  debug: (message: string, data?: any) => {
    if (process.env.NODE_ENV === 'development') {
      console.debug(message, data ? redactObject(data) : '');
    }
  },
};