/**
 * GoHighLevel OAuth Flow Implementation
 * Handles authorization, token exchange, and refresh with encryption
 */

import { createClient } from '@supabase/supabase-js';
import crypto from 'crypto';
import { encrypt, decrypt } from '@/lib/crypto/encryption';
import { safeLog } from '@/lib/utils/redact';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

// GHL OAuth endpoints
const GHL_AUTH_URL = 'https://marketplace.gohighlevel.com/oauth/chooselocation';
const GHL_TOKEN_URL = 'https://services.leadconnectorhq.com/oauth/token';

// OAuth configuration
interface OAuthConfig {
  clientId: string;
  clientSecret: string;
  redirectUri: string;
  scopes: string[];
}

function getOAuthConfig(): OAuthConfig {
  const clientId = process.env.GHL_CLIENT_ID;
  const clientSecret = process.env.GHL_CLIENT_SECRET;
  const redirectUri = process.env.GHL_REDIRECT_URI || `${process.env.NEXT_PUBLIC_APP_URL}/oauth/callback`;
  
  if (!clientId || !clientSecret) {
    throw new Error('Missing GHL OAuth credentials');
  }
  
  return {
    clientId,
    clientSecret,
    redirectUri,
    scopes: [
      'contacts.readonly',
      'contacts.write',
      'locations.readonly',
      'opportunities.readonly',
      'opportunities.write',
    ],
  };
}

/**
 * Generate OAuth authorization URL with state
 * Note: GHL doesn't support PKCE, so we use state for CSRF protection
 */
export function getAuthorizeUrl(): { url: string; state: string } {
  const config = getOAuthConfig();
  const state = crypto.randomBytes(32).toString('hex');
  
  const params = new URLSearchParams({
    client_id: config.clientId,
    redirect_uri: config.redirectUri,
    response_type: 'code',
    scope: config.scopes.join(' '),
    state,
  });
  
  const url = `${GHL_AUTH_URL}?${params.toString()}`;
  
  safeLog.info('Generated OAuth authorization URL', { state });
  
  return { url, state };
}

/**
 * Token response from GHL
 */
interface TokenResponse {
  access_token: string;
  refresh_token: string;
  token_type: string;
  expires_in: number;
  scope: string;
  locationId?: string;
  companyId?: string;
  userId?: string;
  userType?: string;
}

/**
 * Exchange authorization code for tokens
 */
export async function exchangeCode(code: string): Promise<TokenResponse> {
  const config = getOAuthConfig();
  
  safeLog.info('Exchanging authorization code for tokens');
  
  try {
    const response = await fetch(GHL_TOKEN_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        client_id: config.clientId,
        client_secret: config.clientSecret,
        grant_type: 'authorization_code',
        code,
        redirect_uri: config.redirectUri,
      }),
    });
    
    if (!response.ok) {
      const errorText = await response.text();
      safeLog.error('Token exchange failed', { status: response.status, error: errorText });
      throw new Error(`Token exchange failed: ${response.status}`);
    }
    
    const tokens: TokenResponse = await response.json();
    
    safeLog.info('Token exchange successful', {
      locationId: tokens.locationId,
      companyId: tokens.companyId,
      expiresIn: tokens.expires_in,
    });
    
    return tokens;
  } catch (error) {
    safeLog.error('Token exchange error', error);
    throw error;
  }
}

/**
 * Refresh access token using refresh token
 */
export async function refreshAccessToken(refreshToken: string): Promise<TokenResponse> {
  const config = getOAuthConfig();
  
  safeLog.info('Refreshing access token');
  
  try {
    const response = await fetch(GHL_TOKEN_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        client_id: config.clientId,
        client_secret: config.clientSecret,
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
      }),
    });
    
    if (!response.ok) {
      const errorText = await response.text();
      safeLog.error('Token refresh failed', { status: response.status, error: errorText });
      throw new Error(`Token refresh failed: ${response.status}`);
    }
    
    const tokens: TokenResponse = await response.json();
    
    safeLog.info('Token refresh successful', { expiresIn: tokens.expires_in });
    
    return tokens;
  } catch (error) {
    safeLog.error('Token refresh error', error);
    throw error;
  }
}

/**
 * Store encrypted tokens in Supabase
 */
export async function storeTokens(
  locationId: string,
  accessToken: string,
  refreshToken: string,
  expiresIn: number
): Promise<void> {
  const supabase = createClient(supabaseUrl, supabaseServiceKey);
  
  safeLog.info('Storing encrypted tokens', { locationId });
  
  try {
    // Get installation
    const { data: installation, error: installError } = await supabase
      .from('installations')
      .select('id')
      .eq('location_id', locationId)
      .single();
    
    if (installError || !installation) {
      throw new Error('Installation not found');
    }
    
    // Encrypt tokens
    const encryptedAccessToken = encrypt(accessToken);
    const encryptedRefreshToken = encrypt(refreshToken);
    
    // Calculate expiry time (with 5 minute buffer)
    const expiresAt = new Date(Date.now() + (expiresIn - 300) * 1000);
    
    // Get current token version
    const { data: currentToken } = await supabase
      .from('oauth_tokens')
      .select('token_version')
      .eq('installation_id', installation.id)
      .order('token_version', { ascending: false })
      .limit(1)
      .single();
    
    const nextVersion = (currentToken?.token_version || 0) + 1;
    
    // Insert new token version
    const { error: insertError } = await supabase
      .from('oauth_tokens')
      .insert({
        installation_id: installation.id,
        access_token_encrypted: encryptedAccessToken,
        refresh_token_encrypted: encryptedRefreshToken,
        expires_at: expiresAt.toISOString(),
        token_version: nextVersion,
      });
    
    if (insertError) {
      throw insertError;
    }
    
    // Delete old token versions (keep last 2 for safety)
    await supabase
      .from('oauth_tokens')
      .delete()
      .eq('installation_id', installation.id)
      .lt('token_version', nextVersion - 1);
    
    safeLog.info('Tokens stored successfully', {
      locationId,
      version: nextVersion,
      expiresAt: expiresAt.toISOString(),
    });
  } catch (error) {
    safeLog.error('Failed to store tokens', error);
    throw error;
  }
}

/**
 * Get valid access token for a location (with automatic refresh)
 */
export async function getValidAccessToken(locationId: string): Promise<string> {
  const supabase = createClient(supabaseUrl, supabaseServiceKey);
  
  try {
    // Get installation
    const { data: installation, error: installError } = await supabase
      .from('installations')
      .select('id')
      .eq('location_id', locationId)
      .single();
    
    if (installError || !installation) {
      throw new Error('Installation not found');
    }
    
    // Get latest token
    const { data: tokenData, error: tokenError } = await supabase
      .from('oauth_tokens')
      .select('*')
      .eq('installation_id', installation.id)
      .order('token_version', { ascending: false })
      .limit(1)
      .single();
    
    if (tokenError || !tokenData) {
      throw new Error('No tokens found for installation');
    }
    
    // Check if token needs refresh (expires in less than 10 minutes)
    const expiresAt = new Date(tokenData.expires_at);
    const needsRefresh = expiresAt.getTime() - Date.now() < 10 * 60 * 1000;
    
    if (needsRefresh) {
      safeLog.info('Token needs refresh', { locationId, expiresAt });
      return await refreshTokenIfNeeded(locationId);
    }
    
    // Decrypt and return access token
    const accessToken = decrypt(tokenData.access_token_encrypted);
    return accessToken;
  } catch (error) {
    safeLog.error('Failed to get valid access token', error);
    throw error;
  }
}

/**
 * Refresh token if needed with retry logic
 */
export async function refreshTokenIfNeeded(
  locationId: string,
  maxRetries: number = 3
): Promise<string> {
  const supabase = createClient(supabaseUrl, supabaseServiceKey);
  
  let lastError: Error | null = null;
  
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      safeLog.info('Attempting token refresh', { locationId, attempt, maxRetries });
      
      // Get installation
      const { data: installation, error: installError } = await supabase
        .from('installations')
        .select('id')
        .eq('location_id', locationId)
        .single();
      
      if (installError || !installation) {
        throw new Error('Installation not found');
      }
      
      // Get current token
      const { data: tokenData, error: tokenError } = await supabase
        .from('oauth_tokens')
        .select('*')
        .eq('installation_id', installation.id)
        .order('token_version', { ascending: false })
        .limit(1)
        .single();
      
      if (tokenError || !tokenData) {
        throw new Error('No tokens found');
      }
      
      // Decrypt refresh token
      const refreshToken = decrypt(tokenData.refresh_token_encrypted);
      
      // Refresh tokens
      const newTokens = await refreshAccessToken(refreshToken);
      
      // Store new tokens
      await storeTokens(
        locationId,
        newTokens.access_token,
        newTokens.refresh_token,
        newTokens.expires_in
      );
      
      safeLog.info('Token refresh successful', { locationId, attempt });
      
      return newTokens.access_token;
    } catch (error) {
      lastError = error instanceof Error ? error : new Error('Unknown error');
      safeLog.warn('Token refresh attempt failed', {
        locationId,
        attempt,
        error: lastError.message,
      });
      
      // Exponential backoff: 1s, 2s, 4s
      if (attempt < maxRetries) {
        const delay = Math.pow(2, attempt - 1) * 1000;
        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }
  }
  
  safeLog.error('Token refresh failed after all retries', {
    locationId,
    maxRetries,
    error: lastError,
  });
  
  throw lastError || new Error('Token refresh failed');
}