import { NextResponse } from 'next/server';
import { getAuthorizeUrl } from '@/lib/ghl/oauth-flow';
import { safeLog } from '@/lib/utils/redact';

export const dynamic = 'force-dynamic';

/**
 * Start OAuth flow
 * GET /api/oauth/start
 */
export async function GET() {
  try {
    const { url, state } = getAuthorizeUrl();
    
    safeLog.info('OAuth flow started', { state });
    
    return NextResponse.json({
      success: true,
      authUrl: url,
      state,
    });
  } catch (error) {
    safeLog.error('Failed to start OAuth flow', error);
    
    return NextResponse.json(
      {
        success: false,
        error: 'Failed to generate authorization URL',
      },
      { status: 500 }
    );
  }
}